mapper.select:
select u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phone_number, u.sex, u.status,u.DOMAIN_ID,u.language, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.dept_name_en, d.leader ,r.role_name,r.role_name_en from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.status = #{status}
AND u.phone_number like concat('%', #{phoneNumber}, '%')
AND u.create_time BETWEEN #{params.beginTime} AND #{params.endTime}
AND (u.dept_id = #{deptId} OR u.dept_id IN ( WITH
RECURSIVE
tree_param (dept_id,parent_id) as ( select a.dept_id,a.parent_id from sys_dept a where a.dept_id = #{deptId} union all select b.dept_id,b.parent_id from tree_param inner join sys_dept b on tree_param.dept_id= b.parent_id ) select dept_id from tree_param) )
${params.dataScope}

mapper.update:
update sys_user
dept_id = #{deptId}, user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phone_number = #{phoneNumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, language = #{language}, update_time = now()
where user_id = #{userId}

update sys_user
set avatar = #{avatar}
where user_name = #{userName}

update sys_user
set password = #{password}
where user_name = #{userName}

